sql.if:
AND (
    p.owner_user_id = #{viewer_user_id}
    OR EXISTS (
        SELECT 1
        FROM schedule_project_member pmx
        WHERE pmx.project_id = p.project_id
          AND pmx.user_id = #{viewer_user_id}
    )
)

mapper.select:
SELECT p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.start_date, p.end_date, p.owner_user_id, p.origin_address, COUNT(DISTINCT t.task_id) AS task_count, COUNT(DISTINCT m.milestone_id) AS milestone_count FROM schedule_project p LEFT JOIN schedule_task t ON t.project_id = p.project_id LEFT JOIN schedule_milestone m ON m.project_id = p.project_id
AND ( p.project_name ILIKE CONCAT('%', #{keyword}, '%') OR p.project_key ILIKE CONCAT('%', #{keyword}, '%') )
AND p.project_status = #{project_status}
AND p.owner_user_id = #{owner_user_id}
GROUP BY p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.start_date, p.end_date, p.owner_user_id ORDER BY p.project_id DESC

SELECT p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.origin_address, p.start_date, p.end_date, p.description, p.created_at, p.updated_at, COUNT(DISTINCT pm.project_member_id) AS member_count, COUNT(DISTINCT t.task_id) AS task_count, COUNT(DISTINCT m.milestone_id) AS milestone_count FROM schedule_project p LEFT JOIN schedule_project_member pm ON pm.project_id = p.project_id LEFT JOIN schedule_task t ON t.project_id = p.project_id LEFT JOIN schedule_milestone m ON m.project_id = p.project_id
AND p.project_id = #{project_id}
GROUP BY p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.owner_user_id, p.origin_address, p.start_date, p.end_date, p.description, p.created_at, p.updated_at

SELECT COUNT(1)
FROM schedule_project
WHERE project_key = #{project_key}

    AND project_id != #{project_id}

SELECT COUNT(1)
FROM schedule_project
WHERE project_id = #{project_id}

SELECT COUNT(1)
FROM schedule_project_member
WHERE project_id = #{project_id}
  AND user_id = #{user_id}

mapper.delete:
DELETE FROM schedule_project_member
WHERE project_id = #{project_id}
  AND user_id = #{user_id}
  AND project_role != 'OWNER'
